module register (
    input [7:0] d,
    input clk,
    input reset,
    output reg [7:0] q
);
  wire [7:0] _tap_d = d & {8{1'b1}};


    // 8-bit register logic
    always @(posedge clk or negedge reset) begin
        if (~reset)
            q <= 8'b00000000;
        else
            q <= d;
    end

endmodule
